"use client";

import { Separator as RACSeparator } from "react-aria-components";
import { SeparatorStyles } from "./styles";

export interface SeparatorProps
  extends React.ComponentProps<typeof RACSeparator> {}

export function Separator({
  className,
  orientation,
  ...props
}: SeparatorProps) {
  return (
    <RACSeparator
      className={SeparatorStyles({ className })}
      data-orientation={orientation}
      data-slot="separator"
      orientation={orientation}
      {...props}
    />
  );
}

import { cva } from "~/registry/lib/cva";

export const SeparatorStyles = cva({
  base: [
    "shrink-0 bg-border",
    "orientation-horizontal:h-px orientation-horizontal:w-full",
    "orientation-vertical:h-full orientation-vertical:w-px",
  ],
  // TODO: Think about this
  // variants: {
  //   variant: {
  //     menu: "-mx-1 my-1",
  //   },
  // },
});
